```plantuml
@startuml

skinparam classAttributeIconSize 0
skinparam style strictuml

interface HouseBuilder {
  + void buildBasic();
  + void buildBody();
  + void buildRoof();
  + House finish();
}

class CommonHouseBuilder {
  - House house;
  + void buildBasic();
  + void buildBody();
  + void buildRoof();
  + House finish();
}

class LuxuryHouseBuilder {
  - House house;
  + void buildBasic();
  + void buildBody();
  + void buildRoof();
  + House finish();
}

class House {
  - String type;
  - boolean base;
  - boolean body;
  - boolean roof;
}

class Decorate {
  - HouseBuilder houseBuilder;
  + House construct();
}

class Client {
}

note right of Decorate : 具体建造对象
note left of House : 具体产品类

CommonHouseBuilder ..|> HouseBuilder
LuxuryHouseBuilder ..|> HouseBuilder

CommonHouseBuilder o--> House
LuxuryHouseBuilder o--> House

Client --|> Decorate

@enduml
```
